
import { defineComponent, ref, toRefs } from "vue";
import { useRoute } from "vue-router";
import base from "../../../../utils/base64";
import {
  getEntrustHistoryDetail,
  entrustDownload,
} from "../../../../server/http/api/user";
import config from "../../../../server/http/config";
import { DownLoadTask } from "../../../../utils/DownLoad";
const columns = [
  {
    dataIndex: "checkItemName",
    key: "checkItemName",

    title: "检测项",
    slots: { customRender: "checkItemName" },
  },
  {
    title: "检测方法",
    dataIndex: "methodName",
    key: "methodName",
  },
  {
    title: "检测依据",
    key: "standardName",
    dataIndex: "standardName",
    slots: { customRender: "standardName" },
  },

  {
    title: "单价",
    key: "checkPrice",
    dataIndex: "checkPrice",
    slots: { customRender: "checkPrice" },
  },
  {
    title: "检测样次",
    key: "times",
    dataIndex: "times",

    slots: { customRender: "times" },
  },
];
export default defineComponent({
  setup() {
    const route: any = useRoute();
    let detail: any = ref({});
    let samplelist: any = ref([]);
    getEntrustHistoryDetail(route.params.id).then((res: any) => {
      if (res.data.code === 200) {
        //console.log(res.data.data);
        let { data } = res.data;
        detail.value = data;
        samplelist.value = data.samples;
      }
    });
    const download = function () {
      DownLoadTask(route.params.id);
    };
    return {
      detail,
      samplelist,
      download,
      columns,
      base,
    };
  },
});
